Here's a pattern using `MockHttpMessageHandler` to control responses, with proper timeout/cancellation testing:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: pluggable handler for HttpClient
    private sealed class MockHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _send;
        public MockHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> send) => _send = send;
        protected override Task<HttpResponseMessage> SendAsync(HttpRequestMessage r, CancellationToken ct) => _send(r, ct);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHandler((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_On404()
    {
        var handler = new MockHandler((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.NotFound)));

        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // --- Cancellation ---
    [TestMethod]
    public async Task FetchAsync_ThrowsWhenAlreadyCancelled()
    {
        var handler = new MockHandler((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)));

        var fetcher = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsWhenCancelledDuringRequest()
    {
        var handler = new MockHandler(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct); // simulate slow server
            return new HttpResponseMessage(System.Net.HttpStatusCode.OK);
        });

        var fetcher = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Timeout via MSTest ---
    [TestMethod]
    [Timeout(3000)] // hard test-level timeout (ms)
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new MockHandler((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("fast")
            }));

        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }
}
```

**Key points:**

- **Mock at `HttpMessageHandler`**, not `HttpClient` — this avoids needing a third-party mocking library and tests the real `HttpClient` pipeline.
- **`[Timeout(ms)]`** is MSTest's built-in test-level timeout. If the test hangs, MSTest kills it.
- **`CancellationTokenSource(delay)`** tests cancellation *during* an in-flight request — more realistic than pre-cancelling.
- Always **`using`** your `CancellationTokenSource` to avoid leaking the internal timer.
- The mock handler's `Task.Delay(..., ct)` properly observes the token, so cancellation propagates just like a real HTTP call would.
